// Metadata loader — fetches the built labs index (assets/data/labs-index.json,
// generated by scripts/generate-labs-index.js from content/labs/*/lab.json).
// content/ itself is source-only and is never deployed — see docs/new-lab-workflow.md.
let cache = null;

export async function loadLabsIndex() {
  if (cache) return cache;
  const res = await fetch("/assets/data/labs-index.json");
  if (!res.ok) throw new Error(`Failed to load labs index: ${res.status}`);
  cache = await res.json();
  return cache;
}

export async function loadLabMetadata(id) {
  const labs = await loadLabsIndex();
  return labs.find(lab => lab.id === id) ?? null;
}
